def _mount_client(app: FastAPI) -> None:
    if os.environ.get("SERVE_CLIENT", "").lower() not in {"1", "true", "yes"}:
        return

    default_client_dir = Path(__file__).resolve().parent.parent.parent / "client"
    client_dir = Path(os.environ.get("CLIENT_DIR", str(default_client_dir)))
    if client_dir.is_dir():
        app.mount("/", StaticFiles(directory=str(client_dir), html=True), name="client")
